1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	const COMPONENT_PREMIUM = 25;
23	
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_MIN_YEARS = 2;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
32	
33	const calculateItemSurcharges = (item: any, base: number): number => {
34	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
35	  const enchantmentSurcharge =
36	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
37	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
38	      : 0;
39	  return curseSurcharge + enchantmentSurcharge;
40	};
41	
42	const calculateComponentsCost = (items: any[]): number => {
43	  const componentCounts: Record<string, number> = {};
44	  for (const item of items) {
45	    if (COMPONENT_TYPES.has(item.type)) {
46	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
47	    }
48	  }
49	  return Object.values(componentCounts).reduce((total, count) => {
50	    return total + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM);
51	  }, 0);
52	};
53	
54	const calculatePolicyModifiers = (basePremium: number, customer: any, quoteIndex: number): number => {
55	  let modifiers = 0;
56	  if (customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS) {
57	    modifiers -= basePremium * LOYALTY_DISCOUNT_RATE;
58	  }
59	  modifiers += basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
60	  if (quoteIndex > 0) {
61	    modifiers -= basePremium * FOLLOW_UP_DISCOUNT_RATE;
62	  }
63	  return modifiers;
64	};
65	
66	const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): { premium: number } => {
67	  const equipmentItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
68	
69	  const equipmentBasePremium = equipmentItems.reduce(
70	    (sum, item) => sum + (BASE_PREMIUMS[item.type] || 0),
71	    0
72	  );
73	  const itemSurcharges = equipmentItems.reduce(
74	    (sum, item) => sum + calculateItemSurcharges(item, BASE_PREMIUMS[item.type] || 0),
75	    0
76	  );
77	  const componentsCost = calculateComponentsCost(items);
78	
79	  const policyBasePremium = equipmentBasePremium + componentsCost;
80	  const policyModifiers = calculatePolicyModifiers(policyBasePremium, customer, quoteIndex);
81	
82	  return { premium: Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE) };
83	};
84	
85	const COMPONENT_INSURANCE_VALUE = 250;
86	
87	const calculateInsuranceSum = (items: any[]): number => {
88	  return items.reduce((sum, item) => {
89	    if (COMPONENT_TYPES.has(item.type)) {
90	      return sum + COMPONENT_INSURANCE_VALUE;
91	    }
92	    return sum + (INSURANCE_VALUES[item.type] || 0);
93	  }, 0);
94	};
95	
96	const processClaim = (step: any, policies: any[]): { payout: number; remainingCap: number } => {
97	  const policy = policies[step.policy];
98	  const totalPayout = step.incident.damages.reduce((sum: number, damage: any) => {
99	    return sum + Math.max(0, damage.amount - DEDUCTIBLE);
100	  }, 0);
101	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
102	  policy.remainingCap -= cappedPayout;
103	  return { payout: Math.floor(cappedPayout), remainingCap: policy.remainingCap };
104	};
105	
106	export const processScenario = (scenario: any): any => {
107	  const policies: any[] = [];
108	  let quoteIndex = 0;
109	  const results = scenario.steps.map((step: any) => {
110	    if (step.op === "claim") {
111	      return processClaim(step, policies);
112	    }
113	    const result = calculateQuotePremium(step.items, scenario.customer, quoteIndex);
114	    policies.push({
115	      items: step.items,
116	      insuranceSum: calculateInsuranceSum(step.items),
117	      remainingCap: calculateInsuranceSum(step.items) * 2,
118	    });
119	    quoteIndex++;
120	    return result;
121	  });
122	  return { results };
123	};
